 using System.Text.Json;
 using System.Text.Json.Serialization.Metadata;

 // Configure options with the default reflection-based resolver
 var options = new JsonSerializerOptions
 {
     TypeInfoResolver = new DefaultJsonTypeInfoResolver()
 };

 // --- 1. Strongly-typed metadata via the generic GetTypeInfo<T>() ---
 JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
 Console.WriteLine($"Got typed metadata: {personInfo.Type.Name}, kind = {personInfo.Kind}");

 // Serialize using the typed metadata directly
 string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
 Console.WriteLine($"Serialized: {json}");

 // --- 2. Probe without throwing via TryGetTypeInfo ---
 // Person is resolvable (reflection resolver handles any type)
 if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? probed))
 {
     Console.WriteLine($"TryGetTypeInfo(Person) succeeded: {probed!.Type.Name}");
 }

 // Use an options instance with an empty composite resolver (resolves nothing)
 var limited = new JsonSerializerOptions
 {
     TypeInfoResolver = JsonTypeInfoResolver.Combine() // empty — resolves no types
 };

 if (limited.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? missing))
 {
     Console.WriteLine("Unexpectedly found metadata!");
 }
 else
 {
     Console.WriteLine("TryGetTypeInfo(Person) returned false — metadata not available (no throw!)");
 }

 // --- Done ---
 Console.WriteLine("\nBoth patterns demonstrated successfully.");

 public record Person(string Name, int Age);
